<?php
namespace App\Http\Controllers\Api; use App\Http\Controllers\Controller; use App\Http\Resources\CardResource; use App\Models\Card; use Illuminate\Http\Request;
class CardController extends Controller { public function index(){return CardResource::collection(Card::all());} public function store(Request $r){return new CardResource(Card::create($r->validate(['title'=>'required','score'=>'required|numeric|min:0|max:100','image'=>'sometimes|string','deck'=>'sometimes|string'])));} public function show(Card $card){return new CardResource($card);} public function update(Request $r,Card $card){$card->update($r->validate(['title'=>'sometimes','score'=>'sometimes|numeric|min:0|max:100','image'=>'sometimes|string','deck'=>'sometimes|string'])); return new CardResource($card);} public function destroy(Card $card){$card->delete();return response()->noContent();} }
